<template><section class="w97-panel" :style="panelStyle"><div class="w97-titlebar">CAS <input :value="modelValue" @input="emit('update:modelValue',($event.target as HTMLInputElement).value)" @keydown.enter="emit('search')"/><button @click="emit('search')">🔍</button></div><div class="w97-scroll"><div v-for="col in columns" :key="col[0]?.name"><div v-for="item in col" :key="item.name" class="w97-li" :class="{active:selectedIds.includes(item.name)}" @click="emit('item-click',{id:item.name,event:$event})" @contextmenu.prevent="emit('item-contextmenu',{id:item.name,event:$event})">{{ item.displayName }} <small>{{ item.displayModifiedAt }}</small></div></div></div></section></template>
<script setup lang="ts">import type { CSSProperties, PropType } from 'vue'; type Item={name:string;displayName:string;displayModifiedAt:string}; defineProps({paneFocus:Boolean,panelStyle:{type:Object as PropType<CSSProperties>,default:()=>({})},modelValue:{type:String,default:''},queryClass:String,findCompact:Boolean,hint:String,scrollLeft:Number,listMode:String,columns:{type:Array as PropType<Item[][]>,default:()=>[]},selectedIds:{type:Array as PropType<string[]>,default:()=>[]},colWidths:Object,sortKey:String,sortDir:String}); const emit=defineEmits(['activate','open-menu','update:modelValue','search','toggle-sort','start-resize','body-scroll','item-click','item-contextmenu','register-item-ref','register-scroll-el','update:listMode'])</script>
